// Handler creates http.Handler with routing matching OpenAPI spec.
func Handler(si ServerInterface) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{})
}

type ChiServerOptions struct {
	BaseURL          string
	BaseRouter       chi.Router
	Middlewares      []MiddlewareFunc
	ErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

// HandlerFromMux creates http.Handler with routing matching OpenAPI spec based on the provided mux.
func HandlerFromMux(si ServerInterface, r chi.Router) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{
		BaseRouter: r,
	})
}

func HandlerFromMuxWithBaseURL(si ServerInterface, r chi.Router, baseURL string) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{
		BaseURL:    baseURL,
		BaseRouter: r,
	})
}

// HandlerWithOptions creates http.Handler with additional options
func HandlerWithOptions(si ServerInterface, options ChiServerOptions) http.Handler {
	r := options.BaseRouter

	if r == nil {
		r = chi.NewRouter()
	}
	if options.ErrorHandlerFunc == nil {
		options.ErrorHandlerFunc = func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		}
	}
	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandlerFunc:   options.ErrorHandlerFunc,
	}

	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/auth/customer/otp/request", wrapper.RequestOTP)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/auth/customer/otp/verify", wrapper.VerifyOTP)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/auth/organizer/login", wrapper.OrganizerLogin)
	})
	r.Group(func(r chi.Router) {
		r.Delete(options.BaseURL+"/claims/{claimId}", wrapper.ReleaseClaim)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/claims/{claimId}/payments", wrapper.InitializePayment)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/events", wrapper.CreateEvent)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/events/{eventId}", wrapper.GetEvent)
	})
	r.Group(func(r chi.Router) {
		r.Put(options.BaseURL+"/events/{eventId}/activate", wrapper.ActivateEvent)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/events/{eventId}/claims", wrapper.ClaimTicket)
	})
	r.Group(func(r chi.Router) {
		r.Put(options.BaseURL+"/events/{eventId}/end", wrapper.EndEvent)
	})
	r.Group(func(r chi.Router) {
		r.Delete(options.BaseURL+"/events/{eventId}/queue", wrapper.AbandonQueue)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/events/{eventId}/queue", wrapper.JoinQueue)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/events/{eventId}/queue/position", wrapper.GetQueuePosition)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/health", wrapper.HealthCheck)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/webhooks/paystack", wrapper.PaystackWebhook)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/ws/queue/{eventId}", wrapper.QueueWebSocket)
	})

	return r
}

