// StrictServerInterface represents all server handlers.
type StrictServerInterface interface {
	// Request OTP
	// (POST /auth/customer/otp/request)
	RequestOTP(ctx context.Context, request RequestOTPRequestObject) (RequestOTPResponseObject, error)
	// Verify OTP
	// (POST /auth/customer/otp/verify)
	VerifyOTP(ctx context.Context, request VerifyOTPRequestObject) (VerifyOTPResponseObject, error)
	// Organizer login
	// (POST /auth/organizer/login)
	OrganizerLogin(ctx context.Context, request OrganizerLoginRequestObject) (OrganizerLoginResponseObject, error)
	// Release a claim
	// (DELETE /claims/{claimId})
	ReleaseClaim(ctx context.Context, request ReleaseClaimRequestObject) (ReleaseClaimResponseObject, error)
	// Initialize payment
	// (POST /claims/{claimId}/payments)
	InitializePayment(ctx context.Context, request InitializePaymentRequestObject) (InitializePaymentResponseObject, error)
	// Create event
	// (POST /events)
	CreateEvent(ctx context.Context, request CreateEventRequestObject) (CreateEventResponseObject, error)
	// Get event
	// (GET /events/{eventId})
	GetEvent(ctx context.Context, request GetEventRequestObject) (GetEventResponseObject, error)
	// Activate event
	// (PUT /events/{eventId}/activate)
	ActivateEvent(ctx context.Context, request ActivateEventRequestObject) (ActivateEventResponseObject, error)
	// Claim a ticket
	// (POST /events/{eventId}/claims)
	ClaimTicket(ctx context.Context, request ClaimTicketRequestObject) (ClaimTicketResponseObject, error)
	// End event
	// (PUT /events/{eventId}/end)
	EndEvent(ctx context.Context, request EndEventRequestObject) (EndEventResponseObject, error)
	// Abandon queue
	// (DELETE /events/{eventId}/queue)
	AbandonQueue(ctx context.Context, request AbandonQueueRequestObject) (AbandonQueueResponseObject, error)
	// Join queue
	// (POST /events/{eventId}/queue)
	JoinQueue(ctx context.Context, request JoinQueueRequestObject) (JoinQueueResponseObject, error)
	// Get queue position
	// (GET /events/{eventId}/queue/position)
	GetQueuePosition(ctx context.Context, request GetQueuePositionRequestObject) (GetQueuePositionResponseObject, error)
	// Health check
	// (GET /health)
	HealthCheck(ctx context.Context, request HealthCheckRequestObject) (HealthCheckResponseObject, error)
	// Paystack webhook
	// (POST /webhooks/paystack)
	PaystackWebhook(ctx context.Context, request PaystackWebhookRequestObject) (PaystackWebhookResponseObject, error)
	// Queue position WebSocket
	// (GET /ws/queue/{eventId})
	QueueWebSocket(ctx context.Context, request QueueWebSocketRequestObject) (QueueWebSocketResponseObject, error)
}

type StrictHandlerFunc = strictnethttp.StrictHTTPHandlerFunc
type StrictMiddlewareFunc = strictnethttp.StrictHTTPMiddlewareFunc

type StrictHTTPServerOptions struct {
	RequestErrorHandlerFunc  func(w http.ResponseWriter, r *http.Request, err error)
	ResponseErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

func NewStrictHandler(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: StrictHTTPServerOptions{
		RequestErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		},
		ResponseErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusInternalServerError)
		},
	}}
}

func NewStrictHandlerWithOptions(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc, options StrictHTTPServerOptions) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: options}
}

type strictHandler struct {
	ssi         StrictServerInterface
	middlewares []StrictMiddlewareFunc
	options     StrictHTTPServerOptions
}

// RequestOTP operation middleware
func (sh *strictHandler) RequestOTP(w http.ResponseWriter, r *http.Request) {
	var request RequestOTPRequestObject

	var body RequestOTPJSONRequestBody
	if err := json.NewDecoder(r.Body).Decode(&body); err != nil {
		sh.options.RequestErrorHandlerFunc(w, r, fmt.Errorf("can't decode JSON body: %w", err))
		return
	}
	request.Body = &body

	handler := func(ctx context.Context, w http.ResponseWriter, r *http.Request, request interface{}) (interface{}, error) {
		return sh.ssi.RequestOTP(ctx, request.(RequestOTPRequestObject))
	}
	for _, middleware := range sh.middlewares {
		handler = middleware(handler, "RequestOTP")
	}

	response, err := handler(r.Context(), w, r, request)

	if err != nil {
		sh.options.ResponseErrorHandlerFunc(w, r, err)
	} else if validResponse, ok := response.(RequestOTPResponseObject); ok {
		if err := validResponse.VisitRequestOTPResponse(w); err != nil {
			sh.options.ResponseErrorHandlerFunc(w, r, err)
		}
	} else if response != nil {
		sh.options.ResponseErrorHandlerFunc(w, r, fmt.Errorf("unexpected response type: %T", response))
	}
}

